`ifndef SYNTHESIS
    integer sram_init_i;
    initial begin
        for (sram_init_i = 0; sram_init_i < 32768; sram_init_i = sram_init_i + 1)
            sram_mem[sram_init_i] = 32'h0000_0000;
    end
`endif

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            sram_raddr <= {15{1'b0}};
        end else if (sram_cs && (sram_wen == 4'b0000)) begin
            sram_raddr <= sram_addr;
        end
    end

    assign sram_rdata = sram_mem[sram_raddr];

    always @(posedge clk) begin
        if (sram_cs && (|sram_wen)) begin
            if (sram_wen[0]) sram_mem[sram_addr][7:0]   <= sram_wdata[7:0];
            if (sram_wen[1]) sram_mem[sram_addr][15:8]  <= sram_wdata[15:8];
            if (sram_wen[2]) sram_mem[sram_addr][23:16] <= sram_wdata[23:16];
            if (sram_wen[3]) sram_mem[sram_addr][31:24] <= sram_wdata[31:24];
        end
    end
`else
